   164→/* ── Journey Guide ── */
   165→type JourneyState =
   166→  | "no_order"
   167→  | "pending_no_proof"
   168→  | "pending_with_proof"
   169→  | "needs_details"
   170→  | "in_progress"
   171→  | "completed";
   172→
   173→function getJourneyState(orders: any[], projects: any[]): { state: JourneyState; order?: any; project?: any } {
   174→  if (orders.length === 0) return { state: "no_order" };
   175→
   176→  const activeProject = projects.find(p => p.status !== "completed" && p.status !== "closed");
   177→  if (activeProject) {
   178→    if (Number(activeProject.progress || 0) >= 100) return { state: "completed", project: activeProject };
   179→    return { state: "in_progress", project: activeProject };
   180→  }
   181→
   182→  const latestOrder = orders[0];
   183→  if (latestOrder.status === "approved") {
   184→    const hasDetails = latestOrder.businessName && latestOrder.sector;
   185→    if (!hasDetails) return { state: "needs_details", order: latestOrder };
   186→    return { state: "in_progress", order: latestOrder };
   187→  }
   188→
   189→  if (latestOrder.status === "pending") {
   190→    const needsProof = (latestOrder.paymentMethod === "bank_transfer" || latestOrder.paymentMethod === "bank") && !latestOrder.paymentProofUrl;
   191→    if (needsProof) return { state: "pending_no_proof", order: latestOrder };
   192→    return { state: "pending_with_proof", order: latestOrder };
   193→  }
   194→
   195→  return { state: "no_order" };
   196→}
