   212→    { id: 5, label: "التسليم 🎉", desc: "مشروعك جاهز وتحت تصرفك!" },
   213→  ];
   214→
   215→  const doneMap: Record<JourneyState, number> = {
   216→    no_order: 0,
   217→    pending_no_proof: 0,
   218→    pending_with_proof: 1,
   219→    needs_details: 2,
   220→    in_progress: 3,
   221→    completed: 5,
   222→  };
   223→
   224→  const activeMap: Record<JourneyState, number> = {
   225→    no_order: 1,
   226→    pending_no_proof: 1,
   227→    pending_with_proof: 2,
   228→    needs_details: 3,
   229→    in_progress: 4,
   230→    completed: 5,
   231→  };
   232→
   233→  const doneCount = doneMap[state];
   234→  const activeId = activeMap[state];
   235→
   236→  return steps.map(s => ({
   237→    ...s,
   238→    done: s.id <= doneCount,
   239→    active: s.id === activeId && state !== "completed",
   240→  }));
   241→}
